"""L2-regularized multiclass (softmax) logistic regression.

This is the convex model used in Section 6.1 of the paper. Parameters are stored
as a flat vector so any of the from-scratch optimizers can update them uniformly.

Objective (mean cross-entropy + L2):
    J(W) = -(1/N) sum_i log softmax(W x_i)[y_i] + (lambda/2)||W||^2
"""
import numpy as np


def _softmax(z):
    z = z - z.max(axis=1, keepdims=True)
    e = np.exp(z)
    return e / e.sum(axis=1, keepdims=True)


class LogisticRegression:
    def __init__(self, n_features, n_classes, l2=1e-4, fit_intercept=True):
        # ASSUMPTION: L2 strength lambda=1e-4; paper says "L2-regularized" with no
        # value given. [see ambiguity_audit.md]
        self.n_features = n_features
        self.n_classes = n_classes
        self.l2 = l2
        self.fit_intercept = fit_intercept
        self.d = (n_features + (1 if fit_intercept else 0))
        self.dim = self.d * n_classes  # flat parameter dimension

    def init_params(self, seed=0):
        # ASSUMPTION: zero init (paper uses "same parameter initialization when
        # comparing optimizers"; exact scheme unspecified). Zeros keep the
        # comparison fair and the problem convex. [see ambiguity_audit.md]
        return np.zeros(self.dim, dtype=np.float64)

    def _augment(self, X):
        if self.fit_intercept:
            return np.hstack([X, np.ones((X.shape[0], 1))])
        return X

    def _W(self, theta):
        return theta.reshape(self.d, self.n_classes)

    def loss_and_grad(self, theta, X, y):
        """Return (loss, flat_grad) on a (mini)batch X, integer labels y."""
        Xa = self._augment(X)
        W = self._W(theta)
        logits = Xa @ W
        P = _softmax(logits)
        n = X.shape[0]
        # cross-entropy
        ll = -np.log(P[np.arange(n), y] + 1e-12).mean()
        # L2 (do not regularize the intercept row)
        Wreg = W.copy()
        if self.fit_intercept:
            Wreg[-1, :] = 0.0
        loss = ll + 0.5 * self.l2 * np.sum(Wreg * Wreg)
        # gradient
        Y = np.zeros_like(P)
        Y[np.arange(n), y] = 1.0
        grad_W = Xa.T @ (P - Y) / n + self.l2 * Wreg
        return loss, grad_W.reshape(-1)

    def loss(self, theta, X, y):
        return self.loss_and_grad(theta, X, y)[0]

    def predict(self, theta, X):
        logits = self._augment(X) @ self._W(theta)
        return logits.argmax(axis=1)

    def accuracy(self, theta, X, y):
        return float((self.predict(theta, X) == y).mean())

